// Parse Claude's JSON output
const claudeOutput = $input.first().json.output || $input.first().json.text || '';

let outliers = [];
try {
  // Find JSON array in Claude's response
  const jsonMatch = claudeOutput.match(/\[\s*\{[\s\S]*\}\s*\]/);
  if (jsonMatch) {
    outliers = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  console.log('Parse error:', e.message);
  outliers = [{ raw_output: claudeOutput, parse_error: e.message }];
}

return outliers.map(item => ({ json: item }));
